import { useEffect, useMemo, useState } from "react";
import api from "../services/api";
import "./Dashboard.css";
import Navbar from "../components/Navbar";

function Dashboard() {
  const role = localStorage.getItem("role");

  const [items, setItems] = useState([]);
  const [cart, setCart] = useState([]);
  const [search, setSearch] = useState("");
  const [showCart, setShowCart] = useState(false);

  const [name, setName] = useState("");
  const [category, setCategory] = useState("");
  const [price, setPrice] = useState("");
  const [imageUrl, setImageUrl] = useState("");

  // ================= LOAD ITEMS =================
  useEffect(() => {
    fetchItems();
  }, []);

  const fetchItems = async () => {
    try {
      const res = await api.get("/items");
      setItems(res.data || []);
    } catch (err) {
      console.error("Fetch items error:", err);
    }
  };

  // ================= SAFE ID HANDLING =================
  const getId = (item) => item.id || item.itemId;

  // ================= CART LOGIC =================

  const addToCart = (item) => {
    const id = getId(item);

    setCart((prev) => {
      const exist = prev.find((i) => getId(i) === id);

      if (exist) {
        return prev.map((i) =>
          getId(i) === id
            ? { ...i, qty: (i.qty || 1) + 1 }
            : i
        );
      }

      return [...prev, { ...item, id, qty: 1 }];
    });
  };

  const increase = (id) => {
    setCart((prev) =>
      prev.map((i) =>
        getId(i) === id
          ? { ...i, qty: (i.qty || 1) + 1 }
          : i
      )
    );
  };

  const decrease = (id) => {
    setCart((prev) =>
      prev
        .map((i) =>
          getId(i) === id
            ? { ...i, qty: (i.qty || 1) - 1 }
            : i
        )
        .filter((i) => (i.qty || 0) > 0)
    );
  };

  // ================= TOTAL =================
  const total = useMemo(() => {
    return cart.reduce(
      (sum, i) => sum + Number(i.price || 0) * (i.qty || 1),
      0
    );
  }, [cart]);

  // ================= SEARCH + GROUP =================
  const groupedItems = useMemo(() => {
    const filtered = items.filter((item) =>
      (item.name || "").toLowerCase().includes(search.toLowerCase())
    );

    return filtered.reduce((acc, item) => {
      const cat = item.category || "Other";
      if (!acc[cat]) acc[cat] = [];
      acc[cat].push(item);
      return acc;
    }, {});
  }, [items, search]);

  // ================= ADMIN =================
  const addProduct = async () => {
    if (!name || !price) {
      alert("Enter name & price");
      return;
    }

    try {
      await api.post("/items", {
        name,
        category,
        price,
        imageUrl,
      });

      setName("");
      setCategory("");
      setPrice("");
      setImageUrl("");

      fetchItems();
    } catch (err) {
      console.error("Add product error:", err);
    }
  };

  const deleteProduct = async (id) => {
    try {
      await api.delete(`/items/${id}`);
      fetchItems();
    } catch (err) {
      console.error("Delete error:", err);
    }
  };

  // ================= ADMIN UI =================
  if (role === "ROLE_ADMIN") {
    return (
      <div>
        <Navbar />

        <div className="admin-container">
          <h2>🧑‍💼 Admin Dashboard</h2>

          <div className="admin-form">
            <input placeholder="Name" value={name} onChange={(e) => setName(e.target.value)} />
            <input placeholder="Category" value={category} onChange={(e) => setCategory(e.target.value)} />
            <input placeholder="Price" value={price} onChange={(e) => setPrice(e.target.value)} />
            <input placeholder="Image URL" value={imageUrl} onChange={(e) => setImageUrl(e.target.value)} />

            <button onClick={addProduct}>Add Product</button>
          </div>

          <div className="admin-list">
            {items.map((item) => (
              <div key={getId(item)} className="admin-item">
                <span>{item.name} - ₹{item.price}</span>
                <button onClick={() => deleteProduct(getId(item))}>
                  Delete
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  // ================= USER UI =================
  return (
    <div>
      <Navbar />

      <div className="dashboard">

        {/* HEADER */}
        <div className="header">
          <h2>🛒 Grocery Store</h2>

          <input
            className="search"
            placeholder="Search products..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />

          <button onClick={() => setShowCart(!showCart)}>
            Cart ({cart.length})
          </button>
        </div>

        <div className="main">

          {/* PRODUCTS */}
          <div className="products">
            {Object.keys(groupedItems).map((cat) => (
              <div key={cat}>
                <h3>{cat}</h3>

                <div className="grid">
                  {groupedItems[cat].map((item) => (
                    <div className="card" key={getId(item)}>
                      <h4>{item.name}</h4>
                      <p>₹ {item.price}</p>

                      <button onClick={() => addToCart(item)}>
                        Add to Cart
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>

          {/* CART */}
          {showCart && (
            <div className="cart">
              <h3>🛒 Cart</h3>

              {cart.map((item) => (
                <div key={getId(item)} className="cart-item">
                  <p>{item.name}</p>

                  <div>
                    <button onClick={() => decrease(getId(item))}>-</button>
                    <span>{item.qty}</span>
                    <button onClick={() => increase(getId(item))}>+</button>
                  </div>

                  <p>₹ {item.price * item.qty}</p>
                </div>
              ))}

              <h3>Total: ₹{total}</h3>

              <button
                onClick={() => {
                  alert("Order placed 🎉");
                  setCart([]);
                }}
              >
                Checkout
              </button>
            </div>
          )}

        </div>
      </div>
    </div>
  );
}

export default Dashboard;
